<?php

declare(strict_types=1);

namespace Modright;

use PDO;

final class Application
{
    private ?PDO $db = null;
    private ?PackRepository $packs = null;
    private ?JobService $jobs = null;
    private string $cspNonce = '';
    private Translator $translator;
    private ?array $currentUser=null;
    private ?Authorization $authorization=null;
    private string $currentRoute='';

    public static function url(string $route = '', array $query = []): string
    {
        $base = rtrim(str_replace('\\', '/', dirname($_SERVER['SCRIPT_NAME'] ?? '/')), '/');
        $query = array_merge($route !== '' ? ['route' => $route] : [], $query);
        return ($base ?: '') . '/index.php' . ($query ? '?' . http_build_query($query) : '');
    }

    public function run(): void
    {
        $this->translator=Translator::current();
        $this->cspNonce=base64_encode(random_bytes(18));header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
        header('Referrer-Policy: same-origin');
        header("Content-Security-Policy: default-src 'self'; style-src 'self'; script-src 'self'; script-src-elem 'self' 'nonce-".$this->cspNonce."'; script-src-attr 'unsafe-inline'; img-src 'self'; form-action 'self'; frame-ancestors 'none'; base-uri 'self'");
        try {
            $route = trim((string) ($_GET['route'] ?? ''), '/');
            $this->currentRoute=$route;
            if (!Config::installed()) {
                $this->installer(); return;
            }
            $this->db = Database::connect(); Database::migrate($this->db);$this->loadCurrentUser();$this->loadUserLocale();$this->packs = new PackRepository($this->db); $this->jobs = new JobService($this->db, $this->packs);
            if ($route === 'locale') { $this->setLocale(); return; }
            if ($route === 'login') { $this->login(); return; }
            if ($route === 'cron') { $this->cron(); return; }
            Security::requireLogin();
            $this->authorizeRoute($route);
            match ($route) {
                '' => $this->dashboard(),
                'logout' => $this->logout(),
                'packs/create' => $this->createPack(),
                'catalog/minecraft' => $this->minecraftCatalog(),
                'catalog/loaders' => $this->loaderCatalog(),
                'catalog/icon' => $this->catalogIcon(),
                'packs/view' => $this->viewPack(),
                'packs/validate' => $this->validatePack(),
                'packs/settings' => $this->packSettings(),
                'packs/server-settings' => $this->serverSettings(),
                'packs/mod/add' => $this->addMod(),
                'packs/mod/edit' => $this->editMod(),
                'packs/mod/delete' => $this->deleteMod(),
                'packs/delete' => $this->deletePack(),
                'packs/import' => $this->importPack(),
                'packs/import/review' => $this->reviewImport(),
                'packs/import/confirm' => $this->confirmImport(),
                'packs/import/cancel' => $this->cancelImport(),
                'packs/check' => $this->checkUpdates(),
                'packs/sync' => $this->syncFiles(),
                'packs/catalog-sync' => $this->syncCatalog(),
                'packs/migrate' => $this->migrationPlanner(),
                'packs/migrate/results' => $this->migrationResults(),
                'packs/migrate/apply' => $this->applyMigration(),
                'migration/replacements' => $this->migrationReplacements(),
                'packs/apply' => $this->applyUpdates(),
                'packs/build' => $this->buildPack(),
                'packs/rebuild' => $this->rebuildPack(),
                'jobs/view' => $this->viewJob(),
                'jobs/step' => $this->stepJob(),
                'jobs/cancel' => $this->cancelJob(),
                'jobs/retry' => $this->retryJob(),
                'packages/download' => $this->downloadPackage(),
                'backups/restore' => $this->restoreBackup(),
                'settings' => $this->settings(),
                'account' => $this->account(),
                'settings/backup' => $this->downloadBackup(),
                'settings/restore' => $this->restoreMigration(),
                'users' => $this->usersPage(),
                'users/edit' => $this->editUser(),
                'packs/share' => $this->sharePack(),
                'tutorial' => $this->tutorial(),
                'tutorial/update' => $this->updateTutorial(),
                'help' => $this->helpCenter(),
                'status/modrinth' => $this->modrinthStatus(),
                default => throw new HttpException(404, 'Page not found.'),
            };
        } catch (HttpException $e) {
            http_response_code($e->status); $this->page('Error', '<div class="card"><h1>Error ' . $e->status . '</h1><p>' . Security::escape($e->getMessage()) . '</p></div>');
        } catch (\Throwable $e) {
            $errorId = bin2hex(random_bytes(6));
            error_log('[Cogwork Engine ' . $errorId . '] ' . $e->__toString());
            http_response_code(500);
            $this->page('Application error', '<div class="card"><h1>Application error</h1><p>An unexpected error occurred. Reference: ' . Security::escape($errorId) . '</p></div>');
        }
    }

    private function installer(): void
    {
        $checks = ['PHP 8.3+' => PHP_VERSION_ID >= 80300, 'PDO' => extension_loaded('pdo'), 'cURL' => extension_loaded('curl'), 'ZIP' => extension_loaded('zip'), 'JSON' => extension_loaded('json'), 'mbstring' => extension_loaded('mbstring'), 'OpenSSL' => extension_loaded('openssl')];
        $drivers = extension_loaded('pdo') ? PDO::getAvailableDrivers() : []; $checks['SQLite or MySQL PDO driver'] = in_array('sqlite', $drivers, true) || in_array('mysql', $drivers, true);
        try { Config::ensureStorage(); $checks['Writable storage'] = is_writable(MODRIGHT_ROOT . '/storage'); } catch (\Throwable) { $checks['Writable storage'] = false; }
        $error = '';
        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
            Security::verifyCsrf();
            if (in_array(false, $checks, true)) $error = 'Resolve failed environment checks before installing.';
            else {
                try {
                    $driver = (string) ($_POST['driver'] ?? 'sqlite');
                    if (!in_array($driver, ['sqlite', 'mysql'], true) || !in_array($driver, $drivers, true)) throw new \InvalidArgumentException('Selected database driver is unavailable.');
                    $config = ['app_key' => bin2hex(random_bytes(32)), 'cron_token' => bin2hex(random_bytes(32)), 'database' => ['driver' => $driver, 'path' => trim((string) ($_POST['sqlite_path'] ?? 'storage/data/modright.sqlite')), 'host' => trim((string) ($_POST['db_host'] ?? 'localhost')), 'port' => (int) ($_POST['db_port'] ?? 3306), 'name' => trim((string) ($_POST['db_name'] ?? '')), 'user' => trim((string) ($_POST['db_user'] ?? '')), 'password' => (string) ($_POST['db_password'] ?? '')]];
                    if ($driver === 'sqlite') Database::sqlitePath($config['database']['path']);
                    $username = trim((string) ($_POST['username'] ?? 'admin')); $password = (string) ($_POST['password'] ?? '');
                    if (!preg_match('/^[A-Za-z0-9_.-]{3,50}$/', $username) || strlen($password) < 12) throw new \InvalidArgumentException('Use a valid username and a password of at least 12 characters.');
                    Config::write($config); $db = Database::connect($config); Database::migrate($db);
                    $stmt=$db->prepare('INSERT INTO admins (id,username,password_hash,created_at) VALUES (?,?,?,?)'); $stmt->execute([Database::id(),$username,password_hash($password,PASSWORD_DEFAULT),Database::now()]);
                    file_put_contents(MODRIGHT_ROOT . '/storage/installed.lock', Database::now(), LOCK_EX);
                    header('Location: ' . self::url('login')); exit;
                } catch (\Throwable $e) { @unlink(Config::FILE); $error = $e->getMessage(); }
            }
        }
        $checkHtml = '<ul class="checks">'; foreach ($checks as $label=>$ok) $checkHtml .= '<li class="' . ($ok?'ok':'bad') . '">' . ($ok?'✓':'✗') . ' ' . Security::escape($label) . '</li>'; $checkHtml .= '</ul>';
        $body='<div class="card narrow"><h1>Install Cogwork Engine</h1><p>Build, maintain, and migrate modpacks.</p>'.$checkHtml.$this->error($error).'<form method="post" data-database-form>'.$this->csrf().'<label>Database<select name="driver" data-database-driver>';
        if(in_array('sqlite',$drivers,true))$body.='<option value="sqlite">SQLite (recommended)</option>'; if(in_array('mysql',$drivers,true))$body.='<option value="mysql">MySQL</option>';
        $body.='</select></label><details data-sqlite-settings><summary>Advanced SQLite settings</summary><label>Database path<input name="sqlite_path" value="storage/data/modright.sqlite" autocomplete="off"></label><p class="field-help">Relative paths start in the application directory. Absolute paths can place the database outside the public web directory.</p></details><details data-mysql-settings><summary>MySQL settings</summary><label>Host<input name="db_host" value="localhost"></label><label>Port<input name="db_port" type="number" value="3306"></label><label>Database<input name="db_name"></label><label>User<input name="db_user"></label><label>Password<input name="db_password" type="password"></label></details><label>Administrator username<input name="username" value="admin" required></label><label>Administrator password<input name="password" type="password" minlength="12" required></label><button>Install</button></form></div>';
        $this->page('Install', $body, false);
    }

    private function login(): void
    {
        if (!empty($_SESSION['user_id'])||!empty($_SESSION['admin_id'])) { header('Location: '.self::url()); exit; }
        $error='';
        if($_SERVER['REQUEST_METHOD']==='POST'){
            Security::verifyCsrf();
            $locale=Translator::normalize((string)($_POST['locale']??$this->translator->locale()));$this->rememberLocale($locale);
            if(!Security::loginAllowed())$error='Too many login attempts. Try again later.';
            else{$user=(new UserService($this->db))->authenticate((string)($_POST['username']??''),(string)($_POST['password']??''));
                if($user){session_regenerate_id(true);$_SESSION['user_id']=$user['id'];$_SESSION['admin_id']=$user['role']==='admin'?$user['id']:null;$_SESSION['session_version']=(int)$user['session_version'];$_SESSION['login_attempts']=[];$this->saveUserLocale($user['id'],$locale);header('Location: '.self::url($user['tutorial_status']==='not_started'?'tutorial':''));exit;} Security::recordFailure();$error='Invalid credentials.';}
        }
        $this->page('Sign in','<div class="card narrow"><div class="auth-brand"><img src="assets/brand.svg" alt=""><div><strong>Cogwork Engine</strong><span>Build, maintain, and migrate modpacks.</span></div></div><h1>Sign in</h1>'.$this->error($error).'<form method="post">'.$this->csrf().'<label>Username<input name="username" required autofocus></label><label>Password<input name="password" type="password" required></label><label>Language<select name="locale">'.$this->localeOptions().'</select></label><button>Sign in</button></form></div>',false);
    }

    private function logout(): void
    { if($_SERVER['REQUEST_METHOD']!=='POST')throw new HttpException(405,'POST required.');Security::verifyCsrf();$_SESSION=[];session_destroy();header('Location: '.self::url('login'));exit; }

    private function dashboard(): void
    {
        $packs=$this->authorization->packs();$cards='';foreach($packs as$p){$cards.='<article class="card"><h2><a href="'.self::url('packs/view',['id'=>$p['id']]).'">'.Security::escape($p['name']).'</a></h2><p>'.Security::escape($p['version_id']).' · Minecraft '.Security::escape($p['game_version']).' · '.Security::escape($p['loader']).'</p></article>';}
        if(!$cards)$cards='<div class="card empty">No modpacks yet. Create or import one.</div>';
        $body='<div class="heading"><div><h1>Modpacks</h1><p>Manage, update, and package your Modrinth packs.</p></div><div><a class="button secondary" href="'.self::url('packs/import').'">Import</a> <a class="button" href="'.self::url('packs/create').'">New pack</a></div></div><div class="grid">'.$cards.'</div>';
        $this->page('Modpacks',$body);
    }

