    private function loaderCatalog(): void
    { $loader=(string)($_GET['loader']??'');$minecraft=trim((string)($_GET['minecraft']??''));$catalog=new VersionCatalog();$this->catalogResponse($catalog,fn()=>$catalog->loaders($loader,$minecraft)); }

    /** @param callable():list<string> $callback */
