        $packageRows='';$stmt=$this->db->prepare('SELECT * FROM packages WHERE pack_id=? ORDER BY created_at DESC LIMIT 10');$stmt->execute([$pack['id']]);foreach($stmt->fetchAll()as$p)$packageRows.='<tr><td>'.Security::escape($p['version_id']).'</td><td>'.Security::escape($this->translator->bytes((int)$p['size'])).'</td><td><a class="button secondary small" href="'.self::url('packages/download',['id'=>$p['id']]).'">Download</a></td></tr>';
