/div>':'').'<div class="import-actions"><form method="post" action="'.self::url('packs/import/cancel').'">'.$this->csrf().'<input type="hidden" name="id" value="'.$review['id'].'"><button class="secondary">Cancel and delete upload</button></form><form method="post" action="'.self::url('packs/import/confirm').'">'.$this->csrf().'<input type="hidden" name="id" value="'.$review['id'].'"><button>Confirm import</button></form></div>';$this->page('Review import',$body); }

