    private function sharePack(): void
    { $pack=$this->packs->find((string)($_GET['id']??$_POST['id']??''));$auth=$this->authorization;$users=(new UserService($this->db))->all();$error='';if($_SERVER['REQUEST_METHOD']==='POST'){Security::verifyCsrf();try{$userId=(string)$_POST['user_id'];if(isset($_POST['revoke']))$auth->revoke($pack['id'],$userId);elseif(isset($_POST['transfer'])){if(!$auth->admin()&&$auth->owner($pack['id'])!==$auth->user()['id'])throw new HttpException(403,'Access denied.');$auth->assignOwner($pack['id'],$userId);}else$auth->grant($pack['id'],$userId,(string)$_POST['preset'],array_map('strval',$_POST['permissions']??[]));header('Location: '.self::url('packs/share',['id'=>$pack['id']]));exit;}catch(\Throwable$e){$error=$e->getMessage();}}$options='';$owner=$auth->owner($pack['id']);foreach($users as$user)if($user['id']!==$owner&&(int)$user['enabled']===1)$options.='<option value="'.$user['id'].'">'.Security::escape($user['display_name'].' ('.$user['username'].')').'</option>';$checks='';foreach(Authorization::CAPABILITIES as$cap)$checks.='<label class="check"><input type="checkbox" name="permissions[]" value="'.$cap.'"> '.Security::escape(ucwords(str_replace('_',' ',$cap))).'</label>';$rows='';foreach($auth->grants($pack['id'])as$grant){$permissions=json_decode($grant['permissions_json'],true)?:[];$rows.='<tr><td>'.Security::escape($grant['display_name']).'</td><td>'.Security::escape($grant['preset']).'</td><td>'.Security::escape(implode(', ',$permissions)).'</td><td><form method="post">'.$this->csrf().'<input type="hidden" name="id" value="'.$pack['id'].'"><input type="hidden" name="user_id" value="'.$grant['user_id'].'"><button class="danger small" name="revoke" value="1">Revoke</button></form></td></tr>';}$body='<div class="heading"><div><a href="'.self::url('packs/view',['id'=>$pack['id']]).'">← '.Security::escape($pack['name']).'</a><h1>Share pack</h1><p>Grant only the access another user needs.</p></div></div>'.$this->error($error).'<div class="card"><form method="post">'.$this->csrf().'<input type="hidden" name="id" value="'.$pack['id'].'"><label>User<select name="user_id">'.$options.'</select></label><label>Permission preset<select name="preset"><option value="viewer">Viewer</option><option value="contributor">Contributor</option><option value="maintainer">Maintainer</option><option value="custom">Custom</option></select></label><details><summary>Custom permissions</summary>'.$checks.'</details><button>Share pack</button> <button class="secondary" name="transfer" value="1" data-confirm="Transfer ownership to this user?">Transfer ownership</button></form></div><div class="card"><h2>Shared access</h2><table><thead><tr><th>User</th><th>Preset</th><th>Permissions</th><th></th></tr></thead><tbody>'.($rows?:'<tr><td colspan="4">This pack is private.</td></tr>').'</tbody></table></div>';$this->page('Share pack',$body); }

    private function tutorial(): void
    { $user=$this->currentUser;$step=max(0,(int)($_GET['step']??$user['tutorial_step']??0));$steps=[['Welcome to Cogwork Engine','The dashboard contains every pack you own or that another user shared with you.'],['Create or import','Create an empty pack or import an existing .mrpack, then review its contents before saving.'],['Synchronize and validate','Refresh metadata, synchronize files, and run validation before updates or builds.'],['Build and migrate','Create client or server packages, or compare newer Minecraft and loader targets in the migration planner.'],['Sharing and safety','Owners can share precise permissions. Keep backups and test migrated worlds before production.']];if($this->authorization->admin())$steps[]=['Administration','Administrators manage accounts, backups, replacement mappings, and every pack from the header and settings pages.'];$step=min($step,count($steps)-1);[$heading,$description]=$steps[$step];$body='<div class="card narrow tutorial"><span>Step '.($step+1).' of '.count($steps).'</span><h1>'.Security::escape($heading).'</h1><p>'.Security::escape($description).'</p><form method="post" action="'.self::url('tutorial/update').'">'.$this->csrf().'<input type="hidden" name="step" value="'.$step.'"><button class="secondary" name="action" value="skip">Skip tutorial</button> '.($step>0?'<button class="secondary" name="action" value="previous">Previous</button> ':'').'<button name="action" value="'.($step===count($steps)-1?'complete':'next').'">'.($step===count($steps)-1?'Finish':'Next').'</button></form></div>';$this->page('Tutorial',$body); }

    private function updateTutorial(): void
    { if($_SERVER['REQUEST_METHOD']!=='POST')throw new HttpException(405,'POST required.');Security::verifyCsrf();$step=(int)($_POST['step']??0);$action=(string)($_POST['action']??'next');$service=new UserService($this->db);if($action==='skip'){$service->tutorial($this->currentUser['id'],'skipped',$step);header('Location: '.self::url());}elseif($action==='complete'){$service->tutorial($this->currentUser['id'],'completed',$step);header('Location: '.self::url());}else{$next=$action==='previous'?max(0,$step-1):$step+1;$service->tutorial($this->currentUser['id'],'in_progress',$next);header('Location: '.self::url('tutorial',['step'=>$next]));}exit; }

    private function helpCenter(): void
    { $query=mb_strtolower(trim((string)($_GET['q']??'')));$topics=[['getting-started','Getting started','Create or import a pack, refresh its catalog, synchronize files, validate it, and then build a package.'],['mods','Managing mods','Search Modrinth, add exact versions, upload private JARs, and use environment flags to control client and server inclusion.'],['jobs','Background jobs','Keep the job page open or configure cron. Jobs are resumable, cancellable, and safe to retry.'],['server','Server packs','Configure Java, memory, server.properties, EULA state, scripts, overrides, and exclusions before building a server ZIP.'],['migration','Migration planner','Compare Minecraft and loader targets, review blockers and replacements, then create a separate migration copy.'],['sharing','Sharing and permissions','Owners share Viewer, Contributor, Maintainer, or custom capabilities. Administrators can access every pack.'],['backup','Backups and recovery','Download regular backups, retain world backups separately, and validate restored packs before production.'],['glossary','Glossary','Loader: the mod runtime. Override: a file copied into the instance. Profile: a build variant. Environment: client/server support. Dependency: another required project.']];$cards='';foreach($topics as[$slug,$title,$text]){if($query!==''&&!str_contains(mb_strtolower($title.' '.$text),$query))continue;$cards.='<article class="card" id="'.$slug.'"><h2>'.Security::escape($title).'</h2><p>'.Security::escape($text).'</p></article>';}$body='<div class="heading"><div><a href="'.self::url().'">← Modpacks</a><h1>Help center</h1><p>Practical guidance for every Cogwork Engine workflow.</p></div><form method="get"><input type="hidden" name="route" value="help"><input type="search" name="q" value="'.Security::escape($query).'" placeholder="Search help…"><button>Search</button></form></div><div class="grid">'.($cards?:'<div class="card empty">No help topics matched your search.</div>').'</div><div class="card"><form method="post" action="'.self::url('tutorial/update').'">'.$this->csrf().'<input type="hidden" name="step" value="0"><button name="action" value="next">Restart tutorial</button></form><p>Documentation version 1 · Cogwork Engine</p></div>';$this->page('Help center',$body); }

    private function cron(): void
    { $config=Config::load();$token=(string)($_SERVER['HTTP_AUTHORIZATION']??$_GET['token']??'');$token=preg_replace('/^Bearer\s+/i','',$token);if(!hash_equals($config['cron_token'],$token))throw new HttpException(403,'Invalid cron token.');$deadline=microtime(true)+20;$count=0;while(microtime(true)<$deadline&&$count<10){if($this->jobs->nextQueued()===null)break;$count++;}header('Content-Type: application/json');echo json_encode(['processed'=>$count],JSON_THROW_ON_ERROR); }

    private function loadCurrentUser(): void
    { $id=(string)($_SESSION['user_id']??$_SESSION['admin_id']??'');if($id==='')return;try{$user=(new UserService($this->db))->find($id);if((int)$user['enabled']!==1||isset($_SESSION['session_version'])&&(int)$_SESSION['session_version']!==(int)$user['session_version']){$_SESSION=[];return;}$_SESSION['user_id']=$user['id'];$_SESSION['admin_id']=$user['role']==='admin'?$user['id']:null;$_SESSION['session_version']=(int)$user['session_version'];$this->currentUser=$user;$this->authorization=new Authorization($this->db,$user);}catch(\Throwable){$_SESSION=[];} }

    private function authorizeRoute(string $route): void
    {
        if($this->authorization===null)throw new HttpException(403,'Access denied.');
        if(in_array($route,['users','users/edit','migration/replacements','settings','settings/backup','settings/restore'],true)&&!$this->authorization->admin())throw new HttpException(403,'Access denied.');
        $capabilities=['packs/view'=>'view','packs/validate'=>'view','packs/settings'=>'edit_metadata','packs/server-settings'=>'server_settings','packs/mod/add'=>'manage_mods','packs/mod/edit'=>'manage_mods','packs/mod/delete'=>'manage_mods','packs/delete'=>'delete','packs/check'=>'update','packs/sync'=>'synchronize','packs/catalog-sync'=>'synchronize','packs/migrate'=>'migrate','packs/migrate/results'=>'migrate','packs/migrate/apply'=>'migrate','packs/apply'=>'update','packs/build'=>'build','packs/share'=>'share'];
        if(isset($capabilities[$route])){$packId=(string)($_GET['id']??$_POST['id']??'');if($route==='packs/migrate/results'){$scan=(new MigrationService($this->db,new PackRepository($this->db)))->find((string)($_GET['id']??$_POST['scan_id']??''));$packId=(string)$scan['pack_id'];}if($route==='packs/migrate/apply'){$scan=(new MigrationService($this->db,new PackRepository($this->db)))->find((string)($_POST['scan_id']??''));$packId=(string)$scan['pack_id'];}$this->authorization->requirePack($packId,$capabilities[$route]);}
        if(str_starts_with($route,'jobs/')){$jobId=(string)($_GET['id']??$_POST['id']??'');if($route==='jobs/retry')$jobId=(string)($_POST['id']??'');$job=$this->jobs->find($jobId);if(!empty($job['pack_id'])){$jobCapability=$route==='jobs/view'?'view':match($job['type']){'build'=>'build','update_check','apply_updates'=>'update','migration_scan'=>'migrate',default=>'synchronize'};$this->authorization->requirePack((string)$job['pack_id'],$jobCapability);}}
        if(str_starts_with($route,'jobs/')&&empty($job['pack_id'])&&!$this->authorization->admin()){$stmt=$this->db->prepare('SELECT user_id FROM job_actors WHERE job_id=?');$stmt->execute([$jobId]);if($stmt->fetchColumn()!==$this->currentUser['id'])throw new HttpException(403,'Access denied.');}
        if(in_array($route,['packs/import/review','packs/import/confirm','packs/import/cancel'],true)&&!$this->authorization->admin()){$reviewId=(string)($_GET['id']??$_POST['id']??'');$stmt=$this->db->prepare('SELECT user_id FROM import_review_owners WHERE review_id=?');$stmt->execute([$reviewId]);if($stmt->fetchColumn()!==$this->currentUser['id'])throw new HttpException(403,'Access denied.');}
        if($route==='packs/rebuild'){$stmt=$this->db->prepare('SELECT pack_id FROM build_manifests WHERE id=?');$stmt->execute([(string)($_POST['id']??'')]);$packId=$stmt->fetchColumn();if(!$packId||!$this->authorization->can((string)$packId,'build'))throw new HttpException(403,'Access denied.');}
        if($route==='packages/download'){$stmt=$this->db->prepare('SELECT pack_id FROM packages WHERE id=?');$stmt->execute([(string)($_GET['id']??'')]);$packId=$stmt->fetchColumn();if(!$packId||!$this->authorization->can((string)$packId,'build'))throw new HttpException(403,'Access denied.');}
        if($route==='backups/restore'){$stmt=$this->db->prepare('SELECT pack_id FROM backups WHERE id=?');$stmt->execute([(string)($_POST['id']??'')]);$packId=$stmt->fetchColumn();if(!$packId||!$this->authorization->can((string)$packId,'edit_metadata'))throw new HttpException(403,'Access denied.');}
    }

    private function setLocale(): void
    { if($_SERVER['REQUEST_METHOD']!=='POST')throw new HttpException(405,'POST required.');Security::verifyCsrf();$locale=Translator::normalize((string)($_POST['locale']??''));$this->rememberLocale($locale);if(!empty($_SESSION['user_id']))$this->saveUserLocale((string)$_SESSION['user_id'],$locale);header('Location: '.self::url(!empty($_SESSION['user_id'])?'settings':'login'));exit; }

    private function loadUserLocale(): void
    { if($this->currentUser===null)return;$locale=Translator::normalize((string)$this->currentUser['locale']);$_SESSION['locale']=$locale;$this->translator=new Translator($locale); }

    private function saveUserLocale(string $adminId,string $locale): void
    { $stmt=$this->db->prepare('UPDATE users SET locale=?,updated_at=? WHERE id=?');$stmt->execute([$locale,Database::now(),$adminId]); }

    private function rememberLocale(string $locale): void
    { $_SESSION['locale']=$locale;$this->translator=new Translator($locale);setcookie('modright_locale',$locale,['expires'=>time()+31536000,'path'=>'/','secure'=>!empty($_SERVER['HTTPS'])&&$_SERVER['HTTPS']!=='off','httponly'=>true,'samesite'=>'Lax']); }

