        $i18n=['status_unknown'=>$this->translator->text('Status unknown'),'status_failed'=>$this->translator->text('Could not reach the status service'),'processing_next'=>$this->translator->text('Processing next'),'preparing'=>$this->translator->text('Preparing…'),'processed'=>$this->translator->text('Processed'),'retrying'=>$this->translator->text('Retry'),'mods_one'=>$this->translator->plural('mods',1),'mods_many'=>$this->translator->plural('mods',2),'job.file_verified'=>$this->translator->text('job.file_verified'),'job.file_downloaded'=>$this->translator->text('job.file_downloaded'),'job.catalog_saved'=>$this->translator->text('job.catalog_saved'),'job.catalog_failed'=>$this->translator->text('job.catalog_failed')];
        $document='<!doctype html><html lang="'.Security::escape($this->translator->languageTag()).'"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>'.Security::escape($this->translator->text($title)).' · Cogwork Engine</title><link rel="icon" href="assets/favicon.svg" type="image/svg+xml"><link rel="stylesheet" href="assets/app.css"></head><body><a class="skip-link" href="#main-content">Skip to content</a>'.$nav.'<main id="main-content">'.$content.'</main><script nonce="'.Security::escape($this->cspNonce).'">window.ModrightI18n='.json_encode($i18n,JSON_HEX_TAG|JSON_HEX_AMP|JSON_HEX_APOS|JSON_HEX_QUOT|JSON_THROW_ON_ERROR).';</script><script src="assets/app.js"></script></body></html>';echo$this->translator->html($document);
    }
